// File: schema.js
const {
  GraphQLSchema,
  GraphQLObjectType,
  GraphQLList,
  GraphQLInt,
  GraphQLString
} = require('graphql');

// Define AuthorType
const AuthorType = new GraphQLObjectType({
  name: 'Author',
  fields: () => ({
    id: { type: GraphQLInt },
    name: { type: GraphQLString }
  })
});

// Define PostType
const PostType = new GraphQLObjectType({
  name: 'Post',
  fields: () => ({
    id: { type: GraphQLInt },
    title: { type: GraphQLString },
    content: { type: GraphQLString },
    author: {
      type: AuthorType,
      // This resolve function fetches the author for the current post.
      // `post` is the parent object (the Post instance).
      // `context.db` is the PostgreSQL Pool instance passed from express-graphql.
      resolve(post, args, context) {
        return context.db.query('SELECT id, name FROM authors WHERE id = $1', [post.author_id])
          .then(res => res.rows[0]);
      }
    }
  })
});

// Define RootQuery
const RootQuery = new GraphQLObjectType({
  name: 'RootQueryType',
  fields: {
    posts: {
      type: new GraphQLList(PostType),
      // This resolve function fetches all posts from the database.
      resolve(parent, args, context) {
        return context.db.query('SELECT id, title, content, author_id FROM posts')
          .then(res => res.rows);
      }
    }
  }
});

module.exports = new GraphQLSchema({
  query: RootQuery
});

