const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { Pool } = require('pg');
const schema = require('./schema'); // Import our GraphQL schema definition

const app = express();
const port = 4000;

// PostgreSQL Pool setup
// Replace with your actual PostgreSQL connection details
const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'graphql_posts_db',
  password: 'password',
  port: 5432,
});

// Test DB connection
pool.on('connect', () => {
  console.log('Connected to PostgreSQL database');
});

pool.on('error', (err) => {
  console.error('Unexpected error on idle client', err);
  process.exit(-1);
});

// GraphQL endpoint
app.use(
  '/graphql',
  graphqlHTTP({
    schema: schema,
    graphiql: true, // Enable GraphiQL for testing queries in the browser
    context: { db: pool } // Pass the PostgreSQL pool to all GraphQL resolvers
  })
);

// Start the Express server
app.listen(port, () => {
  console.log(`Server running on http://localhost:${port}/graphql`);
  console.log('GraphiQL is available at http://localhost:4000/graphql');
});